// ============================================================
// WF-03: RECORDATORIOS + AUTO-CANCELACION
// Cron cada 1 hora
// ============================================================

const helpers = this.helpers;
const SUPABASE_URL = $env.SUPABASE_URL;
const SUPABASE_KEY = $env.SUPABASE_SERVICE_KEY;
const WA_TOKEN = $env.META_WHATSAPP_TOKEN;
const PHONE_ID = '963190063548521';
const N8N_BASE_URL = $env.WEBHOOK_URL || $env.N8N_HOST || '';

const CONSULTORIO = {
  nombre: 'Policonsultorio Rivadavia',
  direccion: 'Av. Rivadavia 4520, Piso 1, Caballito, CABA',
  mapsLink: 'https://maps.google.com/?q=Av+Rivadavia+4520+CABA'
};

const DIAS = ['Dom','Lun','Mar','Mi\u00e9','Jue','Vie','S\u00e1b'];
const MESES = ['Ene','Feb','Mar','Abr','May','Jun','Jul','Ago','Sep','Oct','Nov','Dic'];
function argDate(d) { return new Date(d.getTime() - 3*60*60*1000); }
function fmtLarga(d) { return `${DIAS[d.getUTCDay()]} ${d.getUTCDate()} de ${MESES[d.getUTCMonth()]}`; }
function fmtHora(d) { return `${String(d.getUTCHours()).padStart(2,'0')}:${String(d.getUTCMinutes()).padStart(2,'0')}`; }

async function supaGet(table, params) {
  try { return await helpers.httpRequest({ method: 'GET', url: `${SUPABASE_URL}/rest/v1/${table}`, qs: params, headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}` } }); }
  catch (e) { return []; }
}

async function supaUpdate(table, filters, data) {
  try { await helpers.httpRequest({ method: 'PATCH', url: `${SUPABASE_URL}/rest/v1/${table}`, qs: filters, headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}`, 'Content-Type': 'application/json' }, body: JSON.stringify({ ...data, updated_at: new Date().toISOString() }) }); }
  catch (e) {}
}

async function sendText(phone, text) {
  try { await helpers.httpRequest({ method: 'POST', url: `https://graph.facebook.com/v21.0/${PHONE_ID}/messages`, headers: { 'Authorization': `Bearer ${WA_TOKEN}`, 'Content-Type': 'application/json' }, body: JSON.stringify({ messaging_product: 'whatsapp', to: phone, type: 'text', text: { body: text } }) }); }
  catch (e) {}
}

async function sendButtons(phone, text, buttons) {
  try { await helpers.httpRequest({ method: 'POST', url: `https://graph.facebook.com/v21.0/${PHONE_ID}/messages`, headers: { 'Authorization': `Bearer ${WA_TOKEN}`, 'Content-Type': 'application/json' }, body: JSON.stringify({ messaging_product: 'whatsapp', to: phone, type: 'interactive', interactive: { type: 'button', body: { text }, action: { buttons: buttons.slice(0,3).map(b => ({ type: 'reply', reply: { id: b.id, title: b.title.substring(0,20) } })) } } }) }); }
  catch (e) {}
}

const now = new Date();
const results = { reminder24h: 0, reminder2h: 0, autoCancelled: 0, errors: [] };

// ============ 1. REMINDER 24HS ============
try {
  const from24 = new Date(now.getTime() + 23*60*60*1000).toISOString();
  const to24 = new Date(now.getTime() + 25*60*60*1000).toISOString();

  const turnos24 = await supaGet('consultorio_turnos', {
    estado: 'eq.agendado',
    reminder_24h_sent: 'eq.false',
    select: 'id,fecha_hora,paciente_id,profesional_id,check_in_token',
    and: `(fecha_hora.gte.${from24},fecha_hora.lte.${to24})`
  });

  for (const t of (turnos24 || [])) {
    try {
      const pac = await supaGet('consultorio_pacientes', { id: `eq.${t.paciente_id}`, select: 'nombre,telefono_wa,obra_social' });
      const prof = await supaGet('consultorio_profesionales', { id: `eq.${t.profesional_id}`, select: 'nombre,especialidad' });
      if (!pac?.[0] || !prof?.[0]) continue;

      const d = argDate(new Date(t.fecha_hora));
      const msg = `Hola ${pac[0].nombre.split(' ')[0]}! Te recuerdo que ma\u00f1ana ten\u00e9s turno:\n\n\ud83d\udcc5 ${fmtLarga(d)}, ${fmtHora(d)} hs\n\ud83d\udc68\u200d\u2695\ufe0f ${prof[0].nombre} \u2014 ${prof[0].especialidad}\n\ud83d\udccd ${CONSULTORIO.direccion}\n\n\u00bfConfirm\u00e1s que vas a asistir?`;

      await sendButtons(pac[0].telefono_wa, msg, [
        { id: 'rem_confirmar', title: 'S\u00ed, confirmo' },
        { id: 'rem_reprogramar', title: 'Reprogramar' },
        { id: 'rem_cancelar', title: 'Cancelar turno' }
      ]);

      await supaUpdate('consultorio_turnos', { id: `eq.${t.id}` }, { reminder_24h_sent: true });

      // Guardar en contexto de conversacion para que WF-02 sepa que es respuesta a reminder
      await supaUpdate('consultorio_conversaciones', { telefono_wa: `eq.${pac[0].telefono_wa}` }, {
        estado: 'respuesta_reminder',
        contexto: { turnoId: t.id, profesionalId: t.profesional_id, profesionalNombre: prof[0].nombre, especialidad: prof[0].especialidad }
      });

      results.reminder24h++;
    } catch (e) { results.errors.push(`24h turno ${t.id}: ${e.message}`); }
  }
} catch (e) { results.errors.push(`24h query: ${e.message}`); }

// ============ 2. REMINDER 2HS ============
try {
  const from2 = new Date(now.getTime() + 1.5*60*60*1000).toISOString();
  const to2 = new Date(now.getTime() + 2.5*60*60*1000).toISOString();

  const turnos2 = await supaGet('consultorio_turnos', {
    estado: 'eq.confirmado',
    reminder_2h_sent: 'eq.false',
    select: 'id,fecha_hora,paciente_id,profesional_id,check_in_token',
    and: `(fecha_hora.gte.${from2},fecha_hora.lte.${to2})`
  });

  for (const t of (turnos2 || [])) {
    try {
      const pac = await supaGet('consultorio_pacientes', { id: `eq.${t.paciente_id}`, select: 'nombre,telefono_wa,obra_social' });
      const prof = await supaGet('consultorio_profesionales', { id: `eq.${t.profesional_id}`, select: 'nombre,especialidad,consultorio' });
      if (!pac?.[0] || !prof?.[0]) continue;

      const d = argDate(new Date(t.fecha_hora));
      const checkinUrl = `${N8N_BASE_URL}/webhook/consultorio-checkin?token=${t.check_in_token}`;

      let msg = `Hola ${pac[0].nombre.split(' ')[0]}! Te esperamos en 2 horas.\n\n`;
      msg += `\ud83d\udcc5 Hoy ${fmtHora(d)} hs \u2014 ${prof[0].nombre}\n`;
      msg += `\ud83d\udccd ${CONSULTORIO.direccion}\n`;
      msg += `\ud83d\uddfa\ufe0f ${CONSULTORIO.mapsLink}\n\n`;
      msg += `Cuando llegues, toc\u00e1 ac\u00e1 para hacer check-in r\u00e1pido:\n\ud83d\udc49 ${checkinUrl}\n\n`;
      msg += `Record\u00e1 traer DNI`;
      if (pac[0].obra_social) msg += ` y credencial de ${pac[0].obra_social}`;
      msg += '.';

      await sendText(pac[0].telefono_wa, msg);
      await supaUpdate('consultorio_turnos', { id: `eq.${t.id}` }, { reminder_2h_sent: true });
      results.reminder2h++;
    } catch (e) { results.errors.push(`2h turno ${t.id}: ${e.message}`); }
  }
} catch (e) { results.errors.push(`2h query: ${e.message}`); }

// ============ 3. AUTO-CANCELACION (6hs antes) ============
try {
  const from6 = new Date(now.getTime() + 5.5*60*60*1000).toISOString();
  const to6 = new Date(now.getTime() + 6.5*60*60*1000).toISOString();

  const turnosNC = await supaGet('consultorio_turnos', {
    estado: 'eq.agendado',
    reminder_24h_sent: 'eq.true',
    select: 'id,fecha_hora,paciente_id,profesional_id',
    and: `(fecha_hora.gte.${from6},fecha_hora.lte.${to6})`
  });

  for (const t of (turnosNC || [])) {
    try {
      const pac = await supaGet('consultorio_pacientes', { id: `eq.${t.paciente_id}`, select: 'nombre,telefono_wa' });
      const prof = await supaGet('consultorio_profesionales', { id: `eq.${t.profesional_id}`, select: 'nombre' });
      if (!pac?.[0]) continue;

      await supaUpdate('consultorio_turnos', { id: `eq.${t.id}` }, { estado: 'auto_cancelado' });

      const d = argDate(new Date(t.fecha_hora));
      await sendText(pac[0].telefono_wa, `Hola ${pac[0].nombre.split(' ')[0]}, como no confirmaste tu turno de hoy a las ${fmtHora(d)} con ${prof?.[0]?.nombre || 'el profesional'}, lo cancelamos autom\u00e1ticamente para que otro paciente pueda usarlo.\n\nSi quer\u00e9s reagendar, escribime cuando quieras.`);

      // Resetear conversacion
      await supaUpdate('consultorio_conversaciones', { telefono_wa: `eq.${pac[0].telefono_wa}` }, { estado: 'inicio', contexto: {} });

      results.autoCancelled++;
    } catch (e) { results.errors.push(`autocancel turno ${t.id}: ${e.message}`); }
  }
} catch (e) { results.errors.push(`autocancel query: ${e.message}`); }

return [{ json: results }];

